//#region src/composables/auth/useCurrentUser.ts
var useCurrentUser = () => {
	const authStore = useAuthStore();
	const commandStore = useCommandStore();
	const apiKeyStore = useApiKeyAuthStore();
	const firebaseUser = computed(() => authStore.currentUser);
	const isApiKeyLogin = computed(() => apiKeyStore.isAuthenticated);
	const isLoggedIn = computed(() => !!isApiKeyLogin.value || firebaseUser.value !== null);
	const resolvedUserInfo = computed(() => {
		if (isApiKeyLogin.value && apiKeyStore.currentUser) return { id: apiKeyStore.currentUser.id };
		if (firebaseUser.value) return { id: firebaseUser.value.uid };
		return null;
	});
	const onUserResolved = (callback) => whenever(resolvedUserInfo, callback, { immediate: true });
	const onTokenRefreshed = (callback) => whenever(() => authStore.tokenRefreshTrigger, callback);
	const onUserLogout = (callback) => {
		watch(resolvedUserInfo, (user, prevUser) => {
			if (prevUser && !user) callback();
		});
	};
	const userDisplayName = computed(() => {
		if (isApiKeyLogin.value) return apiKeyStore.currentUser?.name;
		return firebaseUser.value?.displayName;
	});
	const userEmail = computed(() => {
		if (isApiKeyLogin.value) return apiKeyStore.currentUser?.email;
		return firebaseUser.value?.email;
	});
	const providerName = computed(() => {
		if (isApiKeyLogin.value) return "Comfy API Key";
		const providerId = firebaseUser.value?.providerData[0]?.providerId;
		if (providerId?.includes("google")) return "Google";
		if (providerId?.includes("github")) return "GitHub";
		return providerId;
	});
	const providerIcon = computed(() => {
		if (isApiKeyLogin.value) return "pi pi-key";
		const providerId = firebaseUser.value?.providerData[0]?.providerId;
		if (providerId?.includes("google")) return "pi pi-google";
		if (providerId?.includes("github")) return "pi pi-github";
		return "pi pi-user";
	});
	const isEmailProvider = computed(() => {
		if (isApiKeyLogin.value) return false;
		return firebaseUser.value?.providerData[0]?.providerId === "password";
	});
	const userPhotoUrl = computed(() => {
		if (isApiKeyLogin.value) return null;
		return firebaseUser.value?.photoURL;
	});
	const handleSignOut = async () => {
		if (isApiKeyLogin.value) await apiKeyStore.clearStoredApiKey();
		else await commandStore.execute("Comfy.User.SignOut");
	};
	const handleSignIn = async () => {
		await commandStore.execute("Comfy.User.OpenSignInDialog");
	};
	return {
		loading: authStore.loading,
		isLoggedIn,
		isApiKeyLogin,
		isEmailProvider,
		userDisplayName,
		userEmail,
		userPhotoUrl,
		providerName,
		providerIcon,
		resolvedUserInfo,
		handleSignOut,
		handleSignIn,
		onUserResolved,
		onTokenRefreshed,
		onUserLogout
	};
};
