	async function requireActiveSubscription() {
		await fetchStatus();
		if (!isActiveSubscription.value) subscriptionDialog.show();
	}
	function showSubscriptionDialog() {
		subscriptionDialog.show();
	}
	onBeforeUnmount(() => {
		stopCancelPolling();
	});
