//#region src/composables/billing/useBillingContext.ts
/**
* Unified billing context that automatically switches between legacy (user-scoped)
* and workspace billing based on the active workspace type.
*
* - Personal workspaces use legacy billing via /customers/* endpoints
* - Team workspaces use workspace billing via /billing/* endpoints
*
* The context automatically initializes when the workspace changes and provides
* a unified interface for subscription status, balance, and billing actions.
*
* @example
* ```typescript
* const {
*   type,
*   subscription,
*   balance,
*   isInitialized,
*   initialize,
*   subscribe
* } = useBillingContext()
*
* // Wait for initialization
* await initialize()
*
* // Check subscription status
* if (subscription.value?.isActive) {
*   console.log(`Tier: ${subscription.value.tier}`)
* }
*
* // Check balance
* if (balance.value) {
*   const dollars = balance.value.amountMicros / 1_000_000
*   console.log(`Balance: $${dollars.toFixed(2)}`)
* }
* ```
*/
function useBillingContextInternal() {
	const store = useTeamWorkspaceStore();
	const { flags } = useFeatureFlags();
	const legacyBillingRef = shallowRef(null);
	const workspaceBillingRef = shallowRef(null);
	const getLegacyBilling = () => {
		if (!legacyBillingRef.value) legacyBillingRef.value = useLegacyBilling();
		return legacyBillingRef.value;
	};
	const getWorkspaceBilling = () => {
		if (!workspaceBillingRef.value) workspaceBillingRef.value = useWorkspaceBilling();
		return workspaceBillingRef.value;
	};
	const isInitialized = ref(false);
	const isLoading = ref(false);
	const error = ref(null);
	/**
	* Determines which billing type to use:
	* - If team workspaces feature is disabled: always use legacy (/customers)
	* - If team workspaces feature is enabled:
	*   - Personal workspace: use legacy (/customers)
	*   - Team workspace: use workspace (/billing)
	*/
	const type = computed(() => {
		if (!flags.teamWorkspacesEnabled) return "legacy";
		return store.isInPersonalWorkspace ? "legacy" : "workspace";
	});
	const activeContext = computed(() => type.value === "legacy" ? getLegacyBilling() : getWorkspaceBilling());
	const subscription = computed(() => toValue(activeContext.value.subscription));
	const balance = computed(() => toValue(activeContext.value.balance));
	const plans = computed(() => toValue(activeContext.value.plans));
	const currentPlanSlug = computed(() => toValue(activeContext.value.currentPlanSlug));
	const isActiveSubscription = computed(() => toValue(activeContext.value.isActiveSubscription));
	const isFreeTier = computed(() => subscription.value?.tier === "FREE");
	const billingStatus = computed(() => toValue(activeContext.value.billingStatus));
	const subscriptionStatus = computed(() => toValue(activeContext.value.subscriptionStatus));
	const tier = computed(() => toValue(activeContext.value.tier));
	const renewalDate = computed(() => toValue(activeContext.value.renewalDate));
	function getMaxSeats(tierKey) {
		if (type.value === "legacy") return 1;
		const apiTier = KEY_TO_TIER[tierKey];
		return plans.value.find((p) => p.tier === apiTier && p.duration === "MONTHLY")?.max_seats ?? getTierFeatures(tierKey).maxMembers;
	}
	watch(subscription, (sub) => {
		if (!sub || store.isInPersonalWorkspace) return;
		store.updateActiveWorkspace({
			isSubscribed: sub.isActive && !sub.isCancelled,
			subscriptionPlan: sub.planSlug
		});
	}, { immediate: true });
	watch(() => store.activeWorkspace?.id, async (newWorkspaceId, oldWorkspaceId) => {
		if (!newWorkspaceId) {
			isInitialized.value = false;
			error.value = null;
			return;
		}
		if (newWorkspaceId !== oldWorkspaceId) {
			isInitialized.value = false;
			try {
				await initialize();
			} catch (err) {
				console.error("Failed to initialize billing context:", err);
			}
		}
	}, { immediate: true });
	async function initialize() {
		if (isInitialized.value) return;
		isLoading.value = true;
		error.value = null;
		try {
			await activeContext.value.initialize();
			isInitialized.value = true;
		} catch (err) {
			error.value = err instanceof Error ? err.message : "Failed to initialize billing";
			throw err;
		} finally {
			isLoading.value = false;
		}
	}
	async function fetchStatus() {
		return activeContext.value.fetchStatus();
	}
	async function fetchBalance() {
		return activeContext.value.fetchBalance();
	}
	async function subscribe(planSlug, returnUrl, cancelUrl) {
		return activeContext.value.subscribe(planSlug, returnUrl, cancelUrl);
	}
	async function previewSubscribe(planSlug) {
		return activeContext.value.previewSubscribe(planSlug);
	}
	async function manageSubscription() {
		return activeContext.value.manageSubscription();
	}
	async function cancelSubscription() {
		return activeContext.value.cancelSubscription();
	}
	async function resubscribe() {
		return activeContext.value.resubscribe();
	}
	async function topup(amountCents) {
		return activeContext.value.topup(amountCents);
	}
	async function fetchPlans() {
		return activeContext.value.fetchPlans();
	}
	async function requireActiveSubscription() {
		return activeContext.value.requireActiveSubscription();
	}
	function showSubscriptionDialog() {
		return activeContext.value.showSubscriptionDialog();
	}
	return {
		type,
		isInitialized,
		subscription,
		balance,
		plans,
		currentPlanSlug,
		isLoading,
		error,
		isActiveSubscription,
		isFreeTier,
		billingStatus,
		subscriptionStatus,
		tier,
		renewalDate,
		getMaxSeats,
		initialize,
		fetchStatus,
		fetchBalance,
		subscribe,
		previewSubscribe,
		manageSubscription,
		cancelSubscription,
		resubscribe,
		topup,
		fetchPlans,
		requireActiveSubscription,
		showSubscriptionDialog
	};
}
var useBillingContext = createSharedComposable(useBillingContextInternal);
