//#region src/stores/workspace/colorPaletteStore.ts
var useColorPaletteStore = defineStore("colorPalette", () => {
	const customPalettes = ref({});
	const activePaletteId = ref(DEFAULT_COLOR_PALETTE.id);
	const palettesLookup = computed(() => ({
		...CORE_COLOR_PALETTES,
		...customPalettes.value
	}));
	const palettes = computed(() => Object.values(palettesLookup.value));
	const completedActivePalette = computed(() => completePalette(palettesLookup.value[activePaletteId.value]));
	const addCustomPalette = (palette) => {
		if (palette.id in palettesLookup.value) throw new Error(`Palette with id ${palette.id} already exists`);
		customPalettes.value[palette.id] = palette;
		activePaletteId.value = palette.id;
	};
	const deleteCustomPalette = (id) => {
		if (!(id in customPalettes.value)) throw new Error(`Palette with id ${id} does not exist`);
		delete customPalettes.value[id];
		activePaletteId.value = CORE_COLOR_PALETTES.dark.id;
	};
	const isCustomPalette = (id) => {
		return id in customPalettes.value;
	};
	/**
	* Completes the palette with default values for missing colors.
	*
	* @param palette - The palette to complete.
	* @returns The completed palette.
	*/
	const completePalette = (palette) => {
		if (palette.colors.comfy_base["comfy-menu-bg"] && !palette.colors.comfy_base["comfy-menu-secondary-bg"]) palette.colors.comfy_base["comfy-menu-secondary-bg"] = palette.colors.comfy_base["comfy-menu-bg"];
		const defaultPalette = palette.light_theme ? DEFAULT_LIGHT_COLOR_PALETTE : DEFAULT_DARK_COLOR_PALETTE;
		return {
			...palette,
			colors: {
				...palette.colors,
				node_slot: {
					...defaultPalette.colors.node_slot,
					...palette.colors.node_slot
				},
				litegraph_base: {
					...defaultPalette.colors.litegraph_base,
					...palette.colors.litegraph_base
				},
				comfy_base: {
					...defaultPalette.colors.comfy_base,
					...palette.colors.comfy_base
				}
			}
		};
	};
	return {
		customPalettes,
		activePaletteId,
		palettesLookup,
		palettes,
		completedActivePalette,
		isCustomPalette,
		addCustomPalette,
		deleteCustomPalette,
		completePalette
	};
});
