//#region src/renderer/extensions/minimap/data/LayoutStoreDataSource.ts
var executionStore = null;
/**
* Layout Store data source implementation
*/
var LayoutStoreDataSource = class extends AbstractMinimapDataSource {
	getNodes() {
		const allNodes = layoutStore.getAllNodes().value;
		if (allNodes.size === 0) return [];
		if (!executionStore) executionStore = useExecutionStore();
		const nodeProgressStates = executionStore.nodeLocationProgressStates;
		const nodes = [];
		for (const [nodeId, layout] of allNodes) {
			const graphNode = this.graph?._nodes?.find((n) => String(n.id) === nodeId);
			const executionState = nodeProgressStates[nodeId]?.state ?? null;
			nodes.push({
				id: nodeId,
				x: layout.position.x,
				y: layout.position.y,
				width: layout.size.width,
				height: layout.size.height,
				bgcolor: graphNode?.bgcolor,
				mode: graphNode?.mode,
				hasErrors: graphNode?.has_errors,
				executionState
			});
		}
		return nodes;
	}
	getNodeCount() {
		return layoutStore.getAllNodes().value.size;
	}
	hasData() {
		return this.getNodeCount() > 0;
	}
};
//#endregion
//#region src/renderer/extensions/minimap/data/LiteGraphDataSource.ts
/**
* LiteGraph data source implementation
*/
var LiteGraphDataSource = class extends AbstractMinimapDataSource {
	getNodes() {
		if (!this.graph?._nodes) return [];
		const nodeProgressStates = useExecutionStore().nodeProgressStates;
		return this.graph._nodes.map((node) => {
			const nodeId = String(node.id);
			const executionState = nodeProgressStates[nodeId]?.state ?? null;
			return {
				id: nodeId,
				x: node.pos[0],
				y: node.pos[1],
				width: node.size[0],
				height: node.size[1],
				bgcolor: node.bgcolor,
				mode: node.mode,
				hasErrors: node.has_errors,
				executionState
			};
		});
	}
	getNodeCount() {
		return this.graph?._nodes?.length ?? 0;
	}
	hasData() {
		return this.getNodeCount() > 0;
	}
};
//#endregion
//#region src/renderer/extensions/minimap/data/MinimapDataSourceFactory.ts
/**
* Factory for creating the appropriate data source
*/
var MinimapDataSourceFactory = class {
	static create(graph) {
		if (layoutStore.getAllNodes().value.size > 0) return new LayoutStoreDataSource(graph);
		return new LiteGraphDataSource(graph);
	}
};
