//#region src/renderer/extensions/minimap/minimapCanvasRenderer.ts
/**
* Get theme-aware colors for the minimap
*/
function getMinimapColors() {
	const isLightTheme = useColorPaletteStore().completedActivePalette.light_theme;
	return {
		nodeColor: isLightTheme ? "#3DA8E099" : "#0B8CE999",
		nodeColorDefault: isLightTheme ? "#D9D9D9" : "#353535",
		linkColor: isLightTheme ? "#616161" : "#B3B3B3",
		slotColor: isLightTheme ? "#616161" : "#B3B3B3",
		groupColor: isLightTheme ? "#A2D3EC" : "#1F547A",
		groupColorDefault: isLightTheme ? "#283640" : "#B3C1CB",
		bypassColor: isLightTheme ? "#DBDBDB" : "#4B184B",
		errorColor: "#FF0000",
		runningColor: "#00FF00",
		successColor: "#239B23",
		isLightTheme
	};
}
/**
* Get node color based on settings and node properties (Single Responsibility)
*/
function getNodeColor(node, settings, colors) {
	if (settings.renderBypass && node.mode === LGraphEventMode.BYPASS) return colors.bypassColor;
	if (settings.nodeColors) {
		if (node.bgcolor) return colors.isLightTheme ? adjustColor(node.bgcolor, { lightness: .5 }) : node.bgcolor;
		return colors.nodeColorDefault;
	}
	return colors.nodeColor;
}
/**
* Render groups on the minimap
*/
function renderGroups(ctx, dataSource, offsetX, offsetY, context, colors) {
	const groups = dataSource.getGroups();
	if (groups.length === 0) return;
	for (const group of groups) {
		const x = (group.x - context.bounds.minX) * context.scale + offsetX;
		const y = (group.y - context.bounds.minY) * context.scale + offsetY;
		const w = group.width * context.scale;
		const h = group.height * context.scale;
		let color = colors.groupColor;
		if (context.settings.nodeColors) {
			color = group.color ?? colors.groupColorDefault;
			if (colors.isLightTheme) color = adjustColor(color, { opacity: .5 });
		}
		ctx.fillStyle = color;
		ctx.fillRect(x, y, w, h);
	}
}
/**
* Render nodes on the minimap with performance optimizations
*/
function renderNodes(ctx, dataSource, offsetX, offsetY, context, colors) {
	const nodes = dataSource.getNodes();
	if (nodes.length === 0) return;
	ctx.save();
	const nodesByColor = /* @__PURE__ */ new Map();
	for (const node of nodes) {
		const x = (node.x - context.bounds.minX) * context.scale + offsetX;
		const y = (node.y - context.bounds.minY) * context.scale + offsetY;
		const w = node.width * context.scale;
		const h = node.height * context.scale;
		const color = getNodeColor(node, context.settings, colors);
		if (!nodesByColor.has(color)) nodesByColor.set(color, []);
		nodesByColor.get(color).push({
			x,
			y,
			w,
			h,
			hasErrors: node.hasErrors,
			executionState: node.executionState
		});
	}
	for (const [color, nodes] of nodesByColor) {
		ctx.fillStyle = color;
		for (const node of nodes) ctx.fillRect(node.x, node.y, node.w, node.h);
	}
	ctx.lineWidth = .3;
	for (const nodes of nodesByColor.values()) for (const node of nodes) if (node.hasErrors && context.settings.renderError) {
		ctx.strokeStyle = colors.errorColor;
		ctx.strokeRect(node.x, node.y, node.w, node.h);
	} else if (node.executionState === "running") {
		ctx.strokeStyle = colors.runningColor;
		ctx.strokeRect(node.x, node.y, node.w, node.h);
	} else if (node.executionState === "finished") {
		ctx.strokeStyle = colors.successColor;
		ctx.strokeRect(node.x, node.y, node.w, node.h);
	} else if (node.executionState === "error" && context.settings.renderError) {
		ctx.strokeStyle = colors.errorColor;
		ctx.strokeRect(node.x, node.y, node.w, node.h);
	}
	ctx.restore();
}
/**
* Render connections on the minimap
*/
function renderConnections(ctx, dataSource, offsetX, offsetY, context, colors) {
	const links = dataSource.getLinks();
	if (links.length === 0) return;
	ctx.strokeStyle = colors.linkColor;
	ctx.lineWidth = .3;
	const slotRadius = Math.max(context.scale, .5);
	const connections = [];
	for (const link of links) {
		const x1 = (link.sourceNode.x - context.bounds.minX) * context.scale + offsetX;
		const y1 = (link.sourceNode.y - context.bounds.minY) * context.scale + offsetY;
		const x2 = (link.targetNode.x - context.bounds.minX) * context.scale + offsetX;
		const y2 = (link.targetNode.y - context.bounds.minY) * context.scale + offsetY;
		const outputX = x1 + link.sourceNode.width * context.scale;
		const outputY = y1 + link.sourceNode.height * context.scale * .2;
		const inputX = x2;
		const inputY = y2 + link.targetNode.height * context.scale * .2;
		ctx.beginPath();
		ctx.moveTo(outputX, outputY);
		ctx.lineTo(inputX, inputY);
		ctx.stroke();
		connections.push({
			x1: outputX,
			y1: outputY,
			x2: inputX,
			y2: inputY
		});
	}
	ctx.fillStyle = colors.slotColor;
	for (const conn of connections) {
		ctx.beginPath();
		ctx.arc(conn.x1, conn.y1, slotRadius, 0, Math.PI * 2);
		ctx.fill();
		ctx.beginPath();
		ctx.arc(conn.x2, conn.y2, slotRadius, 0, Math.PI * 2);
		ctx.fill();
	}
}
/**
* Render a graph to a minimap canvas
*/
function renderMinimapToCanvas(canvas, graph, context) {
	const ctx = canvas.getContext("2d");
	if (!ctx) return;
	ctx.clearRect(0, 0, context.width, context.height);
	const dataSource = MinimapDataSourceFactory.create(graph);
	if (!dataSource.hasData()) return;
	const colors = getMinimapColors();
	const offsetX = (context.width - context.bounds.width * context.scale) / 2;
	const offsetY = (context.height - context.bounds.height * context.scale) / 2;
	if (context.settings.showGroups) renderGroups(ctx, dataSource, offsetX, offsetY, context, colors);
	if (context.settings.showLinks) renderConnections(ctx, dataSource, offsetX, offsetY, context, colors);
	renderNodes(ctx, dataSource, offsetX, offsetY, context, colors);
}
