function useTemplateWorkflows() {
	const { t } = useI18n();
	const workflowTemplatesStore = useWorkflowTemplatesStore();
	const dialogStore = useDialogStore();
	const selectedTemplate = ref(null);
	const loadingTemplateId = ref(null);
	const isTemplatesLoaded = computed(() => workflowTemplatesStore.isLoaded);
	const allTemplateGroups = computed(() => workflowTemplatesStore.groupedTemplates);
	/**
	* Loads all template workflows from the API
	*/
	const loadTemplates = async () => {
		if (!workflowTemplatesStore.isLoaded) await workflowTemplatesStore.loadWorkflowTemplates();
		return workflowTemplatesStore.isLoaded;
	};
	/**
	* Selects the first template category as default
	*/
	const selectFirstTemplateCategory = () => {
		if (allTemplateGroups.value.length > 0) {
			const firstCategory = allTemplateGroups.value[0].modules[0];
			selectTemplateCategory(firstCategory);
		}
	};
	/**
	* Selects a template category
	*/
	const selectTemplateCategory = (category) => {
		selectedTemplate.value = category;
		return category !== null;
	};
	/**
	* Gets template thumbnail URL
	*/
	const getTemplateThumbnailUrl = (template, sourceModule, index = "1") => {
		return `${sourceModule === "default" ? api.fileURL(`/templates/${template.name}`) : api.apiURL(`/workflow_templates/${sourceModule}/${template.name}`)}${sourceModule === "default" && index ? `-${index}` : ""}.${template.mediaSubtype}`;
	};
	/**
	* Gets formatted template title
	*/
	const getTemplateTitle = (template, sourceModule) => {
		const fallback = template.title ?? template.name ?? `${sourceModule} Template`;
		return sourceModule === "default" ? template.localizedTitle ?? fallback : fallback;
	};
	/**
	* Gets formatted template description
	*/
	const getTemplateDescription = (template) => {
		return (template.localizedDescription || template.description)?.replace(/[-_]/g, " ").trim() ?? "";
	};
	/**
	* Loads a workflow template
	*/
	const loadWorkflowTemplate = async (id, sourceModule) => {
		if (!isTemplatesLoaded.value) return false;
		loadingTemplateId.value = id;
		let json;
		try {
			if (sourceModule === "all") {
				const template = (allTemplateGroups.value.find((g) => g.label === t("templateWorkflows.category.ComfyUI Examples", "ComfyUI Examples"))?.modules.find((m) => m.moduleName === "all"))?.templates.find((t) => t.name === id);
				if (!template || !template.sourceModule) return false;
				sourceModule = template.sourceModule;
			}
			json = await fetchTemplateJson(id, sourceModule);
			const workflowName = sourceModule === "default" ? t(`templateWorkflows.template.${id}`, id) : id;
			if (isCloud) useTelemetry()?.trackTemplate({
				workflow_name: id,
				template_source: sourceModule
			});
			dialogStore.closeDialog();
			await app.loadGraphData(json, true, true, workflowName, { openSource: "template" });
			return true;
		} catch (error) {
			console.error("Error loading workflow template:", error);
			return false;
		} finally {
			loadingTemplateId.value = null;
		}
	};
	/**
	* Fetches template JSON from the appropriate endpoint
	*/
	const fetchTemplateJson = async (id, sourceModule) => {
		if (sourceModule === "default") return fetch(api.fileURL(`/templates/${id}.json`)).then((r) => r.json());
		else return fetch(api.apiURL(`/workflow_templates/${sourceModule}/${id}.json`)).then((r) => r.json());
	};
	return {
		selectedTemplate,
		loadingTemplateId,
		isTemplatesLoaded,
		allTemplateGroups,
		loadTemplates,
		selectFirstTemplateCategory,
		selectTemplateCategory,
		getTemplateThumbnailUrl,
		getTemplateTitle,
		getTemplateDescription,
		loadWorkflowTemplate
	};
}
