function hasV2DraftHistory(raw) {
	if (!raw) return false;
	try {
		const parsed = JSON.parse(raw);
		const orderLength = Array.isArray(parsed.order) ? parsed.order.length : 0;
		const entriesCount = parsed.entries && typeof parsed.entries === "object" ? Object.keys(parsed.entries).length : 0;
		return orderLength > 0 || entriesCount > 0;
	} catch {
		return false;
	}
}
