		const hasNoLegacyWorkflow = !localStorage.getItem("workflow") && !localStorage.getItem("Comfy.PreviousWorkflow");
		const hasNoV1Drafts = !localStorage.getItem("Comfy.Workflow.Drafts") && !localStorage.getItem("Comfy.Workflow.DraftOrder");
		const hasNoV2DraftIndex = !hasV2DraftHistory(localStorage.getItem("Comfy.Workflow.DraftIndex.v2:personal"));
