//#region src/stores/menuItemStore.ts
var useMenuItemStore = defineStore("menuItem", () => {
	const canvasStore = useCanvasStore();
	const commandStore = useCommandStore();
	const menuItems = ref([]);
	const menuItemHasActiveStateChildren = ref({});
	const hasSeenLinear = ref(false);
	whenever(() => canvasStore.linearMode, () => hasSeenLinear.value = true, {
		immediate: true,
		once: true
	});
	const registerMenuGroup = (path, items) => {
		let currentLevel = menuItems.value;
		for (let i = 0; i < path.length; i++) {
			const segment = path[i];
			let found = currentLevel.find((item) => item.label === segment);
			if (!found) {
				found = {
					label: segment,
					key: segment,
					items: []
				};
				currentLevel.push(found);
			}
			if (!found.items) found.items = [];
			currentLevel = found.items;
		}
		if (currentLevel.length > 0) currentLevel.push({ separator: true });
		currentLevel.push(...items);
		const parentPath = path.join(".");
		if (!menuItemHasActiveStateChildren.value[parentPath]) menuItemHasActiveStateChildren.value[parentPath] = items.some((item) => item.comfyCommand?.active);
	};
	function commandIdToMenuItem(commandId, path) {
		const command = commandStore.getCommand(commandId);
		return {
			command: () => commandStore.execute(command.id),
			label: command.menubarLabel,
			icon: command.icon,
			tooltip: command.tooltip,
			comfyCommand: command,
			parentPath: path?.join(".")
		};
	}
	const registerCommands = (path, commandIds) => {
		registerMenuGroup(path, commandIds.map((id) => commandIdToMenuItem(id, path)));
	};
	const loadExtensionMenuCommands = (extension) => {
		if (!extension.menuCommands) return;
		const extensionCommandIds = new Set(extension.commands?.map((command) => command.id) ?? []);
		extension.menuCommands.forEach((menuCommand) => {
			const commands = menuCommand.commands.filter((command) => extensionCommandIds.has(command));
			if (commands.length) registerCommands(menuCommand.path, commands);
		});
	};
	const registerCoreMenuCommands = () => {
		for (const [path, commands] of CORE_MENU_COMMANDS) registerCommands(path, commands);
	};
	return {
		menuItems,
		registerMenuGroup,
		registerCommands,
		loadExtensionMenuCommands,
		registerCoreMenuCommands,
		menuItemHasActiveStateChildren,
		hasSeenLinear,
		commandIdToMenuItem
	};
});
