//#region src/workbench/utils/nodeDefOrderingUtil.ts
/**
* Gets an ordered array of InputSpec objects based on input_order.
* This is designed to work with V2 format used by litegraphService.
*
* @param nodeDefImpl - The ComfyNodeDefImpl containing both V1 and V2 formats
* @param inputs - The V2 format inputs (flat Record<string, InputSpec>)
* @returns Array of InputSpec objects in the correct order
*/
function getOrderedInputSpecs(nodeDefImpl, inputs) {
	const orderedInputSpecs = [];
	if (!nodeDefImpl.input_order) return Object.values(inputs);
	if (nodeDefImpl.input_order.required) for (const name of nodeDefImpl.input_order.required) {
		const inputSpec = inputs[name];
		if (inputSpec && !inputSpec.isOptional) orderedInputSpecs.push(inputSpec);
	}
	if (nodeDefImpl.input_order.optional) for (const name of nodeDefImpl.input_order.optional) {
		const inputSpec = inputs[name];
		if (inputSpec && inputSpec.isOptional) orderedInputSpecs.push(inputSpec);
	}
	const processedNames = new Set(orderedInputSpecs.map((spec) => spec.name));
	for (const inputSpec of Object.values(inputs)) if (!processedNames.has(inputSpec.name)) orderedInputSpecs.push(inputSpec);
	return orderedInputSpecs;
}
