var useMaskEditorDataStore = defineStore("maskEditorData", () => {
	const inputData = ref(null);
	const outputData = ref(null);
	const sourceNode = ref(null);
	const isLoading = ref(false);
	const loadError = ref(null);
	const hasValidInput = computed(() => inputData.value !== null);
	const hasValidOutput = computed(() => outputData.value !== null);
	const isReady = computed(() => hasValidInput.value && !isLoading.value);
	const reset = () => {
		inputData.value = null;
		outputData.value = null;
		sourceNode.value = null;
		isLoading.value = false;
		loadError.value = null;
	};
	const setLoading = (loading, error) => {
		isLoading.value = loading;
		if (error) loadError.value = error;
	};
	return {
		inputData,
		outputData,
		sourceNode,
		isLoading,
		loadError,
		hasValidInput,
		hasValidOutput,
		isReady,
		reset,
		setLoading
	};
});
