/**
* Adds a handler on paste that extracts and loads images or workflows from pasted JSON data
*/
var usePaste = () => {
	const workspaceStore = useWorkspaceStore();
	const canvasStore = useCanvasStore();
	useEventListener(document, "paste", async (e) => {
		if (shouldIgnoreCopyPaste(e.target)) return;
		if (workspaceStore.shiftDown) return;
		const { canvas } = canvasStore;
		if (!canvas) return;
		let data = e.clipboardData;
		if (!data) throw new Error("No clipboard data on clipboard event");
		data = cloneDataTransfer(data);
		const { items } = data;
		const currentNode = canvas.current_node;
		const isNodeSelected = currentNode?.is_selected;
		const isImageNodeSelected = isNodeSelected && isImageNode(currentNode);
		const isVideoNodeSelected = isNodeSelected && isVideoNode(currentNode);
		const isAudioNodeSelected = isNodeSelected && isAudioNode(currentNode);
		const audioNode = isAudioNodeSelected ? currentNode : null;
		const imageNode = isImageNodeSelected ? currentNode : null;
		const videoNode = isVideoNodeSelected ? currentNode : null;
		for (const item of items) if (item.type.startsWith("image/")) {
			await pasteImageNode(canvas, items, imageNode);
			return;
		} else if (item.type.startsWith("video/")) {
			await pasteVideoNode(canvas, items, videoNode);
			return;
		} else if (item.type.startsWith("audio/")) {
			await pasteAudioNode(canvas, items, audioNode);
			return;
		}
		if (!(isImageNodeSelected || isVideoNodeSelected || isAudioNodeSelected) && pasteClipboardItems(data)) return;
		data = data.getData("text/plain");
		let workflow;
		try {
			data = data.slice(data.indexOf("{"));
			workflow = JSON.parse(data);
		} catch (err) {
			try {
				data = data.slice(data.indexOf("workflow\n"));
				data = data.slice(data.indexOf("{"));
				workflow = JSON.parse(data);
			} catch (error) {
				workflow = null;
			}
		}
		if (workflow && workflow.version && workflow.nodes && workflow.extra) await app.loadGraphData(workflow);
		else {
			if (e.target instanceof HTMLTextAreaElement && e.target.type === "textarea" || e.target instanceof HTMLInputElement && e.target.type === "text") return;
			canvas.pasteFromClipboard();
		}
	});
};
