	/**
	* Handles updates from the API socket
	*/
	addApiUpdateHandlers() {
		api.addEventListener("status", ({ detail }) => {
			this.ui.setStatus(detail);
		});
		api.addEventListener("progress", () => {
			this.canvas.setDirty(true, false);
		});
		api.addEventListener("executing", () => {
			this.canvas.setDirty(true, false);
		});
		api.addEventListener("executed", ({ detail }) => {
			const nodeOutputStore = useNodeOutputStore();
			const executionId = String(detail.display_node || detail.node);
			nodeOutputStore.setNodeOutputsByExecutionId(executionId, detail.output, { merge: detail.merge });
			const node = getNodeByExecutionId(this.rootGraph, executionId);
			if (node && node.onExecuted) node.onExecuted(detail.output);
		});
		api.addEventListener("execution_start", () => {
			triggerCallbackOnAllNodes(this.rootGraph, "onExecutionStart");
		});
		api.addEventListener("execution_error", ({ detail }) => {
			if (detail.exception_message?.includes("Unauthorized: Please login first to use this node.")) useDialogService().showApiNodesSignInDialog([detail.node_type]);
			else if (detail.exception_message?.includes("Payment Required: Please add credits to your account to use this node.")) useDialogService().showTopUpCreditsDialog({ isInsufficientCredits: true });
			else if (useSettingStore().get("Comfy.RightSidePanel.ShowErrorsTab")) useExecutionErrorStore().showErrorOverlay();
			else useDialogService().showExecutionErrorDialog(detail);
			this.canvas.draw(true, true);
		});
		api.addEventListener("b_preview_with_metadata", ({ detail }) => {
			const { blob, displayNodeId, jobId } = detail;
			const { setNodePreviewsByExecutionId, revokePreviewsByExecutionId } = useNodeOutputStore();
			const blobUrl = createSharedObjectUrl(blob);
			useJobPreviewStore().setPreviewUrl(jobId, blobUrl, displayNodeId);
			revokePreviewsByExecutionId(displayNodeId);
			const nodeParents = displayNodeId.split(":");
			for (let i = 1; i <= nodeParents.length; i++) setNodePreviewsByExecutionId(nodeParents.slice(0, i).join(":"), [blobUrl]);
			releaseSharedObjectUrl(blobUrl);
		});
		api.addEventListener("feature_flags", () => {
			useNodeReplacementStore().load();
		});
		api.init();
	}
